#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll,ll>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
priority_queue<PII, vector<PII>, greater<PII> > q;
ll k, n, ans, cnt;
int main(void)
{
	cin >> n >> k;
	for (ll i = 1, temp; i <= n; ++i)
	{
		cin >> temp;
		q.push(mk(temp, 0));
	}
	cnt = n;
	if ((n - 1) % (k - 1)) cnt += (k - 1 - (n - 1) % (k - 1));
	for (ll i = n + 1; i <= cnt; ++i)
	{
		q.push(mk(0, 0));
	}
	while (cnt > 1)
	{
		ll sum = 0, len = 0;
		for (ll i = 1; i <= k; ++i)
		{
			sum += q.top().first;
			len = max(len, q.top().second);
			q.pop();
		}
		q.push(mk(sum, len + 1));
		cnt = cnt - k + 1;
		ans += sum;
	}
	cout << ans << '\n' << q.top().second;
	return false;
}
